# API key storage (in production, use a database)
API_KEYS = {
    'admin_key_12345': {'role': 'admin', 'rate_limit': 100},
    'readonly_key_67890': {'role': 'readonly', 'rate_limit': 50}
}

# Rate limiting storage
rate_limit_store = {}

def validate_api_key(api_key):
    return api_key in API_KEYS

def check_rate_limit(api_key):
    current_time = time.time()
    window = 60  # 1 minute window
    
    if api_key not in rate_limit_store:
        rate_limit_store[api_key] = []
    
    # Remove old requests outside the window
    rate_limit_store[api_key] = [
        req_time for req_time in rate_limit_store[api_key]
        if current_time - req_time < window
    ]
    
    # Check if limit exceeded
    limit = API_KEYS[api_key]['rate_limit']
    if len(rate_limit_store[api_key]) >= limit:
        return False
    
    # Add current request
    rate_limit_store[api_key].append(current_time)
    return True

def require_api_key(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        api_key = request.headers.get('X-API-Key')
        
        if not api_key:
            return jsonify({'error': 'API key required'}), 401
        
        if not validate_api_key(api_key):
            return jsonify({'error': 'Invalid API key'}), 403
        
        if not check_rate_limit(api_key):
            return jsonify({'error': 'Rate limit exceeded'}), 429
        
        request.api_key_info = API_KEYS[api_key]
        return f(*args, **kwargs)
    
    return decorated_function

def sanitize_command(command_str):
    if not command_str or not isinstance(command_str, str):
        raise ValueError('Invalid command format')
    
    # Remove extra whitespace and normalize
    command_str = ' '.join(command_str.split())
    
    # Parse command and arguments
    parts = command_str.split()
    if not parts:
        raise ValueError('Empty command')
    
    command = parts[0].upper()
    args = parts[1:]
    
    # Check if command is blocked
    if command in BLOCKED_COMMANDS:
        raise ValueError(f'Command {command} is not allowed')
    
    # Check if command is in whitelist
    if command not in ALLOWED_COMMANDS:
        raise ValueError(f'Command {command} is not in allowed list')
    
    # Additional validation for specific commands
    if command == 'KEYS':
        # Prevent KEYS * on large databases
        if args and args[0] == '*':
            raise ValueError('KEYS * is not allowed, use specific pattern')
    
    if command == 'FLUSHDB':
        # Require explicit confirmation
        if len(args) < 1 or args[0].upper() != 'CONFIRM':
            raise ValueError('FLUSHDB requires CONFIRM parameter')
        args = []
    
    # Validate arguments don't contain suspicious patterns
    for arg in args:
        if re.search(r'[;\n\r]', str(arg)):
            raise ValueError('Invalid characters in arguments')
    
    return command, args

def validate_key_pattern(key):
    # Ensure keys follow a safe pattern
    if not re.match(r'^[a-zA-Z0-9:_\-\.\*\?\[\]]+$', key):
        raise ValueError('Invalid key pattern')
    return True

@app.route('/api/redis/execute', methods=['POST'])
@require_api_key
def execute_redis_command():
    try:
        # Get command from request
        command_str = request.args.get('command')
        
        if not command_str:
            command_data = request.get_json()
            if command_data:
                command_str = command_data.get('command')
        
        if not command_str:
            return jsonify({'error': 'No command provided'}), 400
        
        # Check role permissions
        role = request.api_key_info['role']
        
        # Sanitize and parse command
        command, args = sanitize_command(command_str)
        
        # Readonly role restrictions
        if role == 'readonly':
            readonly_commands = {'GET', 'HGET', 'HGETALL', 'LRANGE', 'SMEMBERS', 
                               'ZRANGE', 'EXISTS', 'TTL', 'KEYS', 'PING', 'DBSIZE'}
            if command not in readonly_commands:
                return jsonify({'error': 'Insufficient permissions'}), 403
        
        # Validate key patterns if applicable
        if args and command not in {'PING', 'DBSIZE', 'INFO'}:
            validate_key_pattern(args[0])
        
        # Execute command
        result = redis_client.execute_command(command, *args)
        
        # Format response
        return jsonify({
            'success': True,
            'command': command,
            'result': result
        }), 200
        
    except ValueError as e:
        return jsonify({'error': str(e)}), 400
    except redis.RedisError as e:
        return jsonify({'error': f'Redis error: {str(e)}'}), 500
    except Exception as e:
        return jsonify({'error': f'Internal error: {str(e)}'}), 500

@app.route('/api/redis/batch', methods=['POST'])
@require_api_key
def execute_batch_commands():
    try:
        data = request.get_json()
        if not data or 'commands' not in data:
            return jsonify({'error': 'No commands provided'}), 400
        
        commands = data['commands']
        if not isinstance(commands, list) or len(commands) > 10:
            return jsonify({'error': 'Invalid batch size (max 10)'}), 400
        
        results = []
        
        for cmd_str in commands:
            try:
                command, args = sanitize_command(cmd_str)
                
                # Role check
                role = request.api_key_info['role']
                if role == 'readonly':
                    readonly_commands = {'GET', 'HGET', 'HGETALL', 'LRANGE', 
                                       'SMEMBERS', 'ZRANGE', 'EXISTS', 'TTL', 
                                       'KEYS', 'PING', 'DBSIZE'}
                    if command not in readonly_commands:
                        results.append({'error': 'Insufficient permissions', 'command': cmd_str})
                        continue
                
                if args and command not in {'PING', 'DBSIZE', 'INFO'}:
                    validate_key_pattern(args[0])
                
                result = redis_client.execute_command(command, *args)
                results.append({'success': True, 'command': cmd_str, 'result': result})
                
            except Exception as e:
                results.append({'error': str(e), 'command': cmd_str})
        
        return jsonify({'results': results}), 200
        
    except Exception as e:
        return jsonify({'error': str(e)}), 500

